                                {t.wantJar && <div style={{fontSize:"0.75rem",color:"#6c63ff"}}>{t.wantJar.name}</div>}
                                {t.wantCoins>0 && <div style={{color:"#f59e0b",fontSize:"0.8rem"}}>🪙 {t.wantCoins}</div>}
